  def auto_field(form, attribute)
    Auto::Fieldset.new(form, attribute, model: controller_model).render
  end

  def heroicon(name, css_class: "w-5 h-5")
    paths = HEROICONS[name]
    return "" unless paths

    svg_paths = paths.split(" M").map.with_index do |d, i|
      d = "M#{d}" unless i == 0 && d.start_with?("M")
      tag.path(d: d, "stroke-linecap": "round", "stroke-linejoin": "round")
    end.join.html_safe

    tag.svg(svg_paths, class: css_class, fill: "none", stroke: "currentColor", "stroke-width": "1.5", viewBox: "0 0 24 24", xmlns: "http://www.w3.org/2000/svg", "aria-hidden": "true")
  end
